SELECT p.amount, r.rental_id, r.inventory_id, i.film_id, f.film_id, fc.category_id, r.return_date FROM payment p JOIN rental r ON p.rental_id = r.rental_id JOIN inventory i ON r.inventory_id = i.inventory_id JOIN film f ON i.film_id = f.film_id JOIN film_category fc ON f.film_id = fc.film_id WHERE fc.category_id = 1 AND r.return_date IS NOT NULL;